export const TEAMS_BY_CODE: Record<string, Team> = Object.fromEntries(
  TEAMS.map(t => [t.code, t])
)

export const TEAMS_BY_GROUP: Record<string, Team[]> = TEAMS.reduce((acc, t) => {
  if (!acc[t.group]) acc[t.group] = []
  acc[t.group].push(t)
  return acc
}, {} as Record<string, Team[]>)

